#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; long long D; long long H; scanf("%d %lld %lld",&N,&D,&H);
        long long level = 0; int alert = 0;
        for(int i=0;i<N;i++){
            long long a; scanf("%lld",&a);
            if(a>0) level += a;
            else {
                if(level < D) level = 0; else level -= D;
            }
            if(level > H) alert = 1;
        }
        printf(alert?"YES\n":"NO\n");
    }
    return 0;
}

