#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); D = int(next(it)); H = int(next(it))
        level = 0
        alert = False
        for _ in range(N):
            a = int(next(it))
            if a > 0:
                level += a
            else:
                level = max(level - D, 0)
            if level > H:
                alert = True
        out.append('YES' if alert else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

